// ─────────────────────────────────────────────────────────────────────────────
// n8n Code Node: Casino Affiliate Link Extractor
//
// REQUIRED INPUT FIELDS (pass via Set node):
//   - html (string) : full raw HTML of the page
//   - url  (string) : the full URL of the page, e.g. https://www.gambling.com/ca/online-casinos/new
// ─────────────────────────────────────────────────────────────────────────────

const results = [];

for (const item of $input.all()) {

  const html      = item.json.html ?? '';
  const sourceUrl = item.json.url  ?? '';
  const source_id = item.json.source_id  ?? '';
  const country   = item.json.country  ?? '';

  if (!html) {
    results.push({ json: { error: 'No HTML provided. Pass full page HTML as the "html" field.' } });
    continue;
  }

  // ── Extract base domain from sourceUrl (regex-based, no URL parser) ────────
  let baseUrl    = '';
  let baseDomain = '';
  let rootDomain = '';
  const cleanUrl  = sourceUrl.replace(/[\s\uFEFF\u200B\u00A0]/g, '');
  const baseMatch = cleanUrl.match(/^(https?:\/\/[^\/]+)/i);
  if (baseMatch) {
    baseUrl    = baseMatch[1];
    baseDomain = baseUrl.replace(/^https?:\/\/(www\.)?/i, '').toLowerCase();
    const parts = baseDomain.split('.');
    rootDomain  = parts.length >= 2 ? parts.slice(-2).join('.') : baseDomain;
  }

  // Detect if source page is on an affiliate portal subdomain
  // e.g. udenlandske.day-home.dk (non-www, non-root subdomain)
  const isAffiliatPortalSubdomain = rootDomain && baseDomain !== rootDomain && !baseDomain.startsWith('www.');

  // ── Helper: resolve relative hrefs to absolute URLs ───────────────────────
  function resolveHref(href) {
    if (!href) return null;
    href = href.trim();
    if (href.startsWith('http://') || href.startsWith('https://')) return href;
    if (href.startsWith('//'))  return 'https:' + href;
    if (href.startsWith('/'))   return baseUrl + href;
    if (href.startsWith('#') || href.startsWith('mailto:') || href.startsWith('tel:') || href.startsWith('javascript:')) return null;
    // Bare domain — must contain a dot to be a valid domain (avoids single words)
    if (href.includes('.') && !href.includes(' ')) return 'https://' + href;
    return null;
  }

  // ── Helper: extract domain from a full URL ─────────────────────────────────
  function getDomain(href) {
    const m = href.match(/^https?:\/\/(www\.)?([^\/]+)/i);
    return m ? m[2].toLowerCase() : '';
  }

  // ─────────────────────────────────────────────────────────────────────────
  // EXTRACTION PATH A: Standard <a href="..."> tags
  // ─────────────────────────────────────────────────────────────────────────
  const anchorRegex = /<a\s([^>]*)>([\s\S]*?)<\/a>/gi;
  const hrefRegex   = /href=["']([^"']+)["']/i;
  const dataRegex   = /data-(?:casino|brand|name|label|operator)=["']([^"']+)["']/i;
  const imgAltRegex = /<img[^>]+alt=["']([^"']+)["']/i;
  const titleRegex  = /title=["']([^"']+)["']/i;

  const allLinks = [];
  let m;

  while ((m = anchorRegex.exec(html)) !== null) {
    const attrs = m[1];
    const inner = m[2];

    const hrefMatch = hrefRegex.exec(attrs);
    if (!hrefMatch) continue;

    const href = resolveHref(hrefMatch[1].trim());
    if (!href) continue;

    const rawText    = inner.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    const altMatch   = imgAltRegex.exec(inner);
    const anchorText = rawText || (altMatch ? altMatch[1] : '');
    const dataMatch  = dataRegex.exec(attrs);
    const titleMatch = titleRegex.exec(attrs);
    const brand      = dataMatch?.[1] || titleMatch?.[1] || null;
    const classMatch = /class=["']([^"']+)["']/i.exec(attrs);
    const classes    = classMatch ? classMatch[1] : '';

    allLinks.push({ href, anchorText, brand, classes });
  }

  // ── Affiliate link detection ───────────────────────────────────────────────
  const redirectPaths = [
    '/go/', '/visit/', '/out/', '/track/', '/click/', '/redirect/',
    '/aff/', '/refer/', '/forward/', '/creat/', '/play/',
  ];

  const trackingParams = [
    'ref', 'aff', 'affid', 'affiliate', 'tracker', 'btag', 'aid',
    'pid', 'sid', 'click_id', 'clickid', 'subid', 'sub1', 'sub2', 'subid3', 'subid4', 'subid5',
    'token', 'irclickid', 'stag', 'cxd', 'mid', 'promo', 'promocode',
    'referral', 'referrer', 'listid', 'listtype', 'listlocation',
    'listversion', 'list_position', 'ct', 'ctalocation', 'operator_item_id',
    'cta_id', 'seen_item_id', 'pageview_id', 'funnel',
    'creative_id', 'ad_campaign_id',
  ];

  const excludedDomains = [
    'facebook.com', 'twitter.com', 'x.com', 'instagram.com',
    'linkedin.com', 'youtube.com', 'tiktok.com',
    'responsiblegambling.org', 'connexontario.ca', 'camh.ca',
    'gpwa.org', 'mga.org.mt', 'gdcgroup.com', 'certify.gpwa.org',
    'agco.ca', 'kahnawake.com',
  ];

  const ctaKeywords = [
    'play now', 'visit casino', 'visit site', 'visit now', 'claim bonus',
    'get bonus', 'claim offer', 'play here', 'join now', 'register now',
    'get deal', 'claim free spins', 'start playing', 'play for free',
    'get started', 'collect bonus', 'grab bonus', 'try now',
    'play at', 'play',
  ];

  function matchesCta(text) {
    if (!text) return false;
    const cleaned = text.replace(/[^\w\s]/g, '').replace(/\s+/g, ' ').trim().toLowerCase();
    return ctaKeywords.some(k => new RegExp('\\b' + k + '\\b').test(cleaned));
  }

  // CSS class patterns that indicate a CTA button on affiliate portal pages
  const ctaClassPatterns = /\b(btn|button|cta|play|visit|claim|join|register|signup|sign-up)\b/i;

  function isAffiliateLink({ href, anchorText, classes }) {
    if (!href) return false;
    const lhref = href.toLowerCase();
    if (!lhref.startsWith('http')) return false;

    const domain = getDomain(href);
    if (excludedDomains.some(d => domain === d || domain.endsWith('.' + d))) return false;

    const isInternal = rootDomain && (domain === rootDomain || domain.endsWith('.' + rootDomain));
    const isAffiliateSubdomain = isInternal && domain !== baseDomain && !domain.startsWith('www.');
    if (isAffiliateSubdomain) return true;
    if (redirectPaths.some(p => lhref.includes(p))) return true;

    // Decode &amp; before parsing query params
    const qIndex = href.indexOf('?');
    if (qIndex !== -1) {
      const qs = href.slice(qIndex + 1).toLowerCase().replace(/&amp;/gi, '&');
      const paramNames = qs.split('&').map(p => p.split('=')[0]);
      if (trackingParams.some(t => paramNames.includes(t))) return true;
    }

    if (matchesCta(anchorText)) return true;

    // On affiliate portal subdomains, internal links with CTA button classes are affiliate links
    if (isAffiliatPortalSubdomain && isInternal && classes && ctaClassPatterns.test(classes)) return true;

    return false;
  }

  const htmlAffiliateLinks = allLinks.filter(link => isAffiliateLink(link)).map(link => {
    const lhref      = link.href.toLowerCase();
    const domain     = getDomain(link.href);
    const isInternal = rootDomain && (domain === rootDomain || domain.endsWith('.' + rootDomain));
    let category     = 'External + Tracking Param';

    if (redirectPaths.some(p => lhref.includes(p))) {
      category = isInternal ? 'Internal Redirect' : 'External Redirect';
    } else if (isAffiliatPortalSubdomain && isInternal && link.classes && ctaClassPatterns.test(link.classes)) {
      category = 'Portal CTA';
    } else {
      if (matchesCta(link.anchorText || '')) category = isInternal ? 'Internal CTA' : 'External CTA';
    }

    return {
      href:       link.href,
      anchorText: link.anchorText,
      brand:      link.brand,
      category,
      cssClasses: link.classes || null,
      source:     'html',
    };
  });

  // ─────────────────────────────────────────────────────────────────────────
  // EXTRACTION PATH B: Any data attribute on any element
  // Scans ALL attribute values for affiliate URLs regardless of attribute name
  // (data-casino-url, data-href, data-link, data-url, etc.)
  // Handles: https://, //, bare domain (rooster-partner.com/xyz)
  // ─────────────────────────────────────────────────────────────────────────
  const dataAttrLinks = [];

  const tagRegex  = /<([a-z][a-z0-9-]*)\s([^>]+)>/gi;
  const attrRegex = /([\w-]+)=["']([^"']{4,})["']/gi;

  while ((m = tagRegex.exec(html)) !== null) {
    const tagName   = m[1].toLowerCase();
    const attrBlock = m[2];

    // Skip <a> tags — already handled in Path A
    if (tagName === 'a') continue;
    // Skip tags that won't contain affiliate links
    if (['script', 'style', 'link', 'meta', 'img'].includes(tagName)) continue;

    let attrMatch;
    attrRegex.lastIndex = 0;

    const foundUrls = [];
    let brandName   = null;
    let cssClasses  = null;

    while ((attrMatch = attrRegex.exec(attrBlock)) !== null) {
      const attrName = attrMatch[1].toLowerCase();
      const attrVal  = attrMatch[2].trim();

      if (attrName === 'class') { cssClasses = attrVal; continue; }

      // Collect brand/name hints from common data attributes
      if (['data-casino-name', 'data-name', 'data-brand', 'data-label', 'data-operator'].includes(attrName)) {
        brandName = attrVal;
      }

      // Resolve value as URL and check if it's an affiliate link
      const resolved = resolveHref(attrVal);
      if (resolved && isAffiliateLink({ href: resolved, anchorText: brandName })) {
        foundUrls.push({ attrName, href: resolved });
      }
    }

    // Extract URLs from onclick="location.href='URL'" / window.location patterns
    const onclickMatch = /\bonclick\s*=\s*["'](?:[^"']*?)(?:window\.)?location(?:\.href)?\s*=\s*['"]([^'"]+)['"]/i.exec(attrBlock);
    if (onclickMatch) {
      const resolved = resolveHref(onclickMatch[1]);
      if (resolved && isAffiliateLink({ href: resolved, anchorText: brandName })) {
        foundUrls.push({ attrName: 'onclick', href: resolved });
      }
    }

    for (const { attrName, href } of foundUrls) {
      dataAttrLinks.push({
        href,
        anchorText: brandName || null,
        brand:      brandName || null,
        category:   'Data Attribute',
        cssClasses,
        source:     'data_attr',
        attrName,
      });
    }
  }

  // ─────────────────────────────────────────────────────────────────────────
  // EXTRACTION PATH C: __NEXT_DATA__ JSON (Next.js sites)
  // ─────────────────────────────────────────────────────────────────────────
  const nextDataLinks = [];
  let nextDataFound = false;
  let nextDataError = null;
  const nextDataMatch = html.match(/<script[^>]+id=["']__NEXT_DATA__["'][^>]*>([\s\S]*?)<\/script>/i);

  if (nextDataMatch) {
    nextDataFound = true;
    try {
      const nextJson      = JSON.parse(nextDataMatch[1]);
      const affiliateKeys = ['claimurl', 'affiliateurl', 'offerurl', 'trackingurl', 'clickurl', 'bonusurl', 'dealurl'];

      function isAffiliateLinkFromJson(key, val) {
        const lkey = key.toLowerCase();
        if (affiliateKeys.some(k => lkey.includes(k))) return true;

        const lval = val.toLowerCase();
        if (redirectPaths.some(p => lval.includes(p))) return true;

        const qIdx = val.indexOf('?');
        if (qIdx !== -1) {
          const qs = val.slice(qIdx + 1).toLowerCase().replace(/&amp;/gi, '&').replace(/\\u0026/gi, '&');
          const paramNames = qs.split('&').map(p => p.split('=')[0]);
          if (trackingParams.some(t => paramNames.includes(t))) return true;
        }
        const domain = getDomain(val);
        if (excludedDomains.some(d => domain === d || domain.endsWith('.' + d))) return false;
        return false;
      }

      function walkJson(obj) {
        if (!obj || typeof obj !== 'object') return;
        for (const [key, val] of Object.entries(obj)) {
          if (typeof val === 'string') {
            const resolved = resolveHref(val);
            if (resolved && isAffiliateLinkFromJson(key, resolved)) {
              const siblingText = obj.name || obj.claim || obj.label || obj.title || null;
              nextDataLinks.push({
                href:       resolved,
                anchorText: siblingText,
                brand:      obj.name || null,
                category:   'Next.js Data',
                cssClasses: null,
                source:     'next_data',
                jsonKey:    key,
              });
            }
          } else if (typeof val === 'object') {
            walkJson(val);
          }
        }
      }

      walkJson(nextJson);
    } catch (e) {
      nextDataError = e.message || String(e);
    }
  }

  // ─────────────────────────────────────────────────────────────────────────
  // Merge all paths, deduplicate by href, and output
  // ─────────────────────────────────────────────────────────────────────────
  const combined  = [...htmlAffiliateLinks, ...dataAttrLinks, ...nextDataLinks];
  const seenHrefs = new Set();
  const categorised = combined.filter(({ href }) => {
    if (seenHrefs.has(href)) return false;
    seenHrefs.add(href);
    return true;
  });

  results.push({
    json: {
      source_id,
      sourceUrl,
      baseUrl,
      country,
      totalLinksScanned:   allLinks.length,
      affiliateLinksFound: categorised.length,
      affiliateLinks:      categorised,
      nextDataFound,
      nextDataError,
    },
  });
}

return results;

// ─────────────────────────────────────────────────────────────────────────────
// n8n Code Node: Casino Affiliate Link Extractor based on Domain Partners
//
// REQUIRED INPUT FIELDS (pass via Set node):
//   - html      (string) : full raw HTML of the page
//   - url       (string) : the full URL of the page
//   - source_id (number) : source identifier
//   - country   (string) : country code
// ─────────────────────────────────────────────────────────────────────────────

const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.affiliateLinksHolder)) {
  staticData.affiliateLinksHolder = [];
}

const results = [];

// ── Partner domain whitelist (from n8n global variable) ───────────────────
const PARTNER_DOMAINS = $vars.ROOSTER_PARTNER_DOMAINS.split(',').map(d => d.trim().toLowerCase());

for (const item of $input.all()) {

  const html      = item.json.html ?? '';
  const sourceUrl = item.json.url  ?? '';
  const source_id = item.json.source_id ?? '';
  const country   = item.json.country ?? '';

  if (!html) {
    results.push({ json: { error: 'No HTML provided. Pass full page HTML as the "html" field.' } });
    continue;
  }

  // ── Extract base domain ───────────────────────────────────────────────────
  let baseUrl = '', baseDomain = '', rootDomain = '';
  const cleanUrl  = sourceUrl.replace(/[\s\uFEFF\u200B\u00A0]/g, '');
  const baseMatch = cleanUrl.match(/^(https?:\/\/[^\/]+)/i);
  if (baseMatch) {
    baseUrl    = baseMatch[1];
    baseDomain = baseUrl.replace(/^https?:\/\/(www\.)?/i, '').toLowerCase();
    const parts = baseDomain.split('.');
    rootDomain  = parts.length >= 2 ? parts.slice(-2).join('.') : baseDomain;
  }

  // Detect if source page is on an affiliate portal subdomain
  const isAffiliatPortalSubdomain = rootDomain && baseDomain !== rootDomain && !baseDomain.startsWith('www.');

  // ── Helpers ───────────────────────────────────────────────────────────────
  function resolveHref(href) {
    if (!href) return null;
    href = href.trim();
    if (href.startsWith('http://') || href.startsWith('https://')) return href;
    if (href.startsWith('//')) return 'https:' + href;
    if (href.startsWith('/'))  return baseUrl + href;
    if (href.startsWith('#') || href.startsWith('mailto:') || href.startsWith('tel:') || href.startsWith('javascript:')) return null;
    // Bare domain — check if it starts with a known partner domain
    const lhref = href.toLowerCase();
    if (PARTNER_DOMAINS.some(pd => lhref.startsWith(pd))) return 'https://' + href;
    return null;
  }

  function getDomain(href) {
    const m = href.match(/^https?:\/\/(www\.)?([^\/]+)/i);
    return m ? m[2].toLowerCase() : '';
  }

  function containsPartnerDomain(href) {
    const lhref = href.toLowerCase();
    return PARTNER_DOMAINS.some(pd => {
      const domain = getDomain(href);
      if (domain === pd || domain.endsWith('.' + pd)) return true;
      if (lhref.includes(pd)) return true;
      return false;
    });
  }

  function getMatchedPartner(href) {
    return PARTNER_DOMAINS.find(pd => {
      const d = getDomain(href);
      if (d === pd || d.endsWith('.' + pd)) return true;
      if (href.toLowerCase().includes(pd)) return true;
      return false;
    }) || null;
  }

  // ── Shared detection config ───────────────────────────────────────────────
  const redirectPaths = [
    '/go/', '/visit/', '/out/', '/track/', '/click/', '/redirect/',
    '/aff/', '/refer/', '/forward/', '/creat/', '/play/',
  ];

  const trackingParams = [
    'ref', 'aff', 'affid', 'affiliate', 'tracker', 'btag', 'aid',
    'pid', 'sid', 'click_id', 'clickid', 'subid', 'sub1', 'sub2', 'subid3', 'subid4', 'subid5',
    'token', 'irclickid', 'stag', 'cxd', 'mid', 'promo', 'promocode',
    'referral', 'referrer', 'listid', 'listtype', 'listlocation',
    'listversion', 'list_position', 'ct', 'ctalocation', 'operator_item_id',
    'cta_id', 'seen_item_id', 'pageview_id', 'funnel',
    'creative_id', 'ad_campaign_id',
  ];

  const excludedDomains = [
    'facebook.com', 'twitter.com', 'x.com', 'instagram.com',
    'linkedin.com', 'youtube.com', 'tiktok.com',
    'responsiblegambling.org', 'connexontario.ca', 'camh.ca',
    'gpwa.org', 'mga.org.mt', 'gdcgroup.com', 'certify.gpwa.org',
    'agco.ca', 'kahnawake.com',
  ];

  const ctaKeywords = [
    'play now', 'visit casino', 'visit site', 'visit now', 'claim bonus',
    'get bonus', 'claim offer', 'play here', 'join now', 'register now',
    'get deal', 'claim free spins', 'start playing', 'play for free',
    'get started', 'collect bonus', 'grab bonus', 'try now',
    'play at', 'play',
  ];

  function matchesCta(text) {
    if (!text) return false;
    const cleaned = text.replace(/[^\w\s]/g, '').replace(/\s+/g, ' ').trim().toLowerCase();
    return ctaKeywords.some(k => new RegExp('\\b' + k + '\\b').test(cleaned));
  }

  // CSS class patterns that indicate a CTA button on affiliate portal pages
  const ctaClassPatterns = /\b(btn|button|cta|play|visit|claim|join|register|signup|sign-up)\b/i;

  function isAffiliateLink({ href, anchorText, classes }) {
    if (!href) return false;
    const lhref = href.toLowerCase();
    if (!lhref.startsWith('http')) return false;

    const domain    = getDomain(href);
    if (excludedDomains.some(d => domain === d || domain.endsWith('.' + d))) return false;

    const isInternal = rootDomain && (domain === rootDomain || domain.endsWith('.' + rootDomain));
    if (isInternal && domain !== baseDomain && !domain.startsWith('www.')) return true;
    if (redirectPaths.some(p => lhref.includes(p))) return true;

    const qIndex = href.indexOf('?');
    if (qIndex !== -1) {
      const qs = href.slice(qIndex + 1).toLowerCase().replace(/&amp;/gi, '&');
      const paramNames = qs.split('&').map(p => p.split('=')[0]);
      if (trackingParams.some(t => paramNames.includes(t))) return true;
    }

    if (matchesCta(anchorText)) return true;

    // On affiliate portal subdomains, internal links with CTA button classes are affiliate links
    if (isAffiliatPortalSubdomain && isInternal && classes && ctaClassPatterns.test(classes)) return true;

    return false;
  }

  // ─────────────────────────────────────────────────────────────────────────
  // EXTRACTION PATH A: Standard <a href="..."> tags
  // ─────────────────────────────────────────────────────────────────────────
  const anchorRegex = /<a\s([^>]*)>([\s\S]*?)<\/a>/gi;
  const hrefRegex   = /href=["']([^"']+)["']/i;
  const dataRegex   = /data-(?:casino|brand|name|label|operator)=["']([^"']+)["']/i;
  const imgAltRegex = /<img[^>]+alt=["']([^"']+)["']/i;
  const titleRegex  = /title=["']([^"']+)["']/i;

  const allLinks = [];
  let m;

  while ((m = anchorRegex.exec(html)) !== null) {
    const attrs = m[1];
    const inner = m[2];
    const hrefMatch = hrefRegex.exec(attrs);
    if (!hrefMatch) continue;

    const href       = resolveHref(hrefMatch[1].trim());
    if (!href) continue;

    const rawText    = inner.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    const altMatch   = imgAltRegex.exec(inner);
    const anchorText = rawText || (altMatch ? altMatch[1] : '');
    const dataMatch  = dataRegex.exec(attrs);
    const titleMatch = titleRegex.exec(attrs);
    const brand      = dataMatch?.[1] || titleMatch?.[1] || null;
    const classMatch = /class=["']([^"']+)["']/i.exec(attrs);
    const classes    = classMatch ? classMatch[1] : '';

    allLinks.push({ href, anchorText, brand, classes });
  }

  const htmlAffiliateLinks = allLinks
    .filter(link => isAffiliateLink(link) && containsPartnerDomain(link.href))
    .map(link => {
      const lhref      = link.href.toLowerCase();
      const domain     = getDomain(link.href);
      const isInternal = rootDomain && (domain === rootDomain || domain.endsWith('.' + rootDomain));
      let category     = 'External + Tracking Param';
      if (redirectPaths.some(p => lhref.includes(p))) {
        category = isInternal ? 'Internal Redirect' : 'External Redirect';
      } else if (isAffiliatPortalSubdomain && isInternal && link.classes && ctaClassPatterns.test(link.classes)) {
        category = 'Portal CTA';
      } else {
        if (matchesCta(link.anchorText || '')) category = isInternal ? 'Internal CTA' : 'External CTA';
      }
      return {
        href:          link.href,
        anchorText:    link.anchorText,
        brand:         link.brand,
        partnerDomain: getMatchedPartner(link.href),
        category,
        cssClasses:    link.classes || null,
        source:        'html',
      };
    });

  // ─────────────────────────────────────────────────────────────────────────
  // EXTRACTION PATH B: Any data attribute on any element
  // Scans ALL attribute values for partner domain URLs regardless of
  // attribute name (data-casino-url, data-href, data-link, data-url, etc.)
  // Handles: https://, //, bare domain (rooster-partner.com/xyz)
  // ─────────────────────────────────────────────────────────────────────────
  const dataAttrLinks = [];

  // Match any opening tag and capture all its attributes as a block
  const tagRegex  = /<([a-z][a-z0-9-]*)\s([^>]+)>/gi;
  // Match individual attribute key="value" pairs within a tag
  const attrRegex = /([\w-]+)=["']([^"']{4,})["']/gi;

  while ((m = tagRegex.exec(html)) !== null) {
    const tagName  = m[1].toLowerCase();
    const attrBlock = m[2];

    // Skip <a> tags — already handled in Path A
    if (tagName === 'a') continue;

    // Skip <script>, <style>, <link>, <meta>, <img> — not affiliate links
    if (['script', 'style', 'link', 'meta', 'img'].includes(tagName)) continue;

    let attrMatch;
    attrRegex.lastIndex = 0;

    const foundUrls   = [];
    let brandName     = null;
    let cssClasses    = null;
    const attrEntries = {};

    while ((attrMatch = attrRegex.exec(attrBlock)) !== null) {
      const attrName = attrMatch[1].toLowerCase();
      const attrVal  = attrMatch[2].trim();

      if (attrName === 'class') { cssClasses = attrVal; continue; }

      // Collect brand/name hints
      if (['data-casino-name', 'data-name', 'data-brand', 'data-label', 'data-operator'].includes(attrName)) {
        brandName = attrVal;
      }

      attrEntries[attrName] = attrVal;

      // Resolve the value as a URL
      const resolved = resolveHref(attrVal);
      if (resolved && containsPartnerDomain(resolved)) {
        foundUrls.push({ attrName, href: resolved });
      }
    }

    // Extract URLs from onclick="location.href='URL'" / window.location patterns
    const onclickMatch = /\bonclick\s*=\s*["'](?:[^"']*?)(?:window\.)?location(?:\.href)?\s*=\s*['"]([^'"]+)['"]/i.exec(attrBlock);
    if (onclickMatch) {
      const resolved = resolveHref(onclickMatch[1]);
      if (resolved && containsPartnerDomain(resolved)) {
        foundUrls.push({ attrName: 'onclick', href: resolved });
      }
    }

    for (const { attrName, href } of foundUrls) {
      dataAttrLinks.push({
        href,
        anchorText:    brandName || null,
        brand:         brandName || null,
        partnerDomain: getMatchedPartner(href),
        category:      'Data Attribute',
        cssClasses,
        source:        'data_attr',
        attrName,
      });
    }
  }

  // ─────────────────────────────────────────────────────────────────────────
  // EXTRACTION PATH C: __NEXT_DATA__ JSON (Next.js sites)
  // ─────────────────────────────────────────────────────────────────────────
  const nextDataLinks = [];
  let nextDataFound = false;
  let nextDataError = null;
  const nextDataMatch = html.match(/<script[^>]+id=["']__NEXT_DATA__["'][^>]*>([\s\S]*?)<\/script>/i);

  if (nextDataMatch) {
    nextDataFound = true;
    try {
      const nextJson      = JSON.parse(nextDataMatch[1]);
      const affiliateKeys = ['claimurl', 'affiliateurl', 'offerurl', 'trackingurl', 'clickurl', 'bonusurl', 'dealurl'];

      function isAffiliateLinkFromJson(key, val) {
        const lkey = key.toLowerCase();
        if (affiliateKeys.some(k => lkey.includes(k))) return true;

        const lval = val.toLowerCase();
        if (redirectPaths.some(p => lval.includes(p))) return true;

        const qIdx = val.indexOf('?');
        if (qIdx !== -1) {
          const qs = val.slice(qIdx + 1).toLowerCase().replace(/&amp;/gi, '&').replace(/\\u0026/gi, '&');
          const paramNames = qs.split('&').map(p => p.split('=')[0]);
          if (trackingParams.some(t => paramNames.includes(t))) return true;
        }
        return false;
      }

      function walkJson(obj) {
        if (!obj || typeof obj !== 'object') return;
        for (const [key, val] of Object.entries(obj)) {
          if (typeof val === 'string') {
            const resolved = resolveHref(val);
            if (resolved && containsPartnerDomain(resolved) && isAffiliateLinkFromJson(key, val)) {
              const siblingText = obj.name || obj.claim || obj.label || obj.title || null;
              nextDataLinks.push({
                href:          resolved,
                anchorText:    siblingText,
                brand:         obj.name || null,
                partnerDomain: getMatchedPartner(resolved),
                category:      'Next.js Data',
                cssClasses:    null,
                source:        'next_data',
                jsonKey:       key,
              });
            }
          } else if (typeof val === 'object') {
            walkJson(val);
          }
        }
      }

      walkJson(nextJson);
    } catch (e) {
      nextDataError = e.message || String(e);
    }
  }

  // ─────────────────────────────────────────────────────────────────────────
  // Merge all paths, deduplicate by href, output
  // ─────────────────────────────────────────────────────────────────────────
  const combined    = [...htmlAffiliateLinks, ...dataAttrLinks, ...nextDataLinks];
  const seenHrefs   = new Set();
  const categorised = combined.filter(({ href }) => {
    if (seenHrefs.has(href)) return false;
    seenHrefs.add(href);
    return true;
  });

  const output = {
    source_id,
    sourceUrl,
    baseUrl,
    country,
    totalLinksScanned:   allLinks.length,
    affiliateLinksFound: categorised.length,
    affiliateLinks:      categorised,
    nextDataFound,
    nextDataError,
  };

  staticData.affiliateLinksHolder.push(output);
  results.push({ json: output });
}

return results;

